import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'insurance-flowise',
});

// Flowise chatflow configuration
const chatflowConfig = {
  nodes: [...],
  callbacks: {
    onChainStart: async (input) => {
      return vex.guard('insurance-underwriting', {
        input,
        rules: ['no-discrimination', 'pii-redaction'],
      });
    },
    onChainEnd: async (output) => {
      const result = await vex.validate('claims-decision', {
        output,
        context: { requireExplainability: true },
      });
      return result.isValid ? output : { error: result.issues };
    },
  },
};

// In Flowise RAG node callback
const validateRetrieval = async (docs: Document[]) => {
  const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

  const result = await vex.evaluate({
    span: 'rag-retrieval',
    input: { query: chatflowInput.query },
    output: docs.map(d => d.pageContent),
    rules: [
      {
        type: 'relevance',
        threshold: 0.75,
        domain: 'insurance-policy'
      },
      {
        type: 'pii-scan',
        action: 'redact',
        fields: ['ssn', 'medical_history']
      }
    ]
  });

  return result.validDocs;
};

// Agent handoff callback
const handoffGuardrail = async (fromAgent: string, toAgent: string, context: any) => {
  const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

  const audit = await vex.audit({
    event: 'agent-handoff',
    metadata: {
      from: fromAgent,
      to: toAgent,
      hasConsent: context.policyholderConsent,
      piiFields: Object.keys(context.customerData || {}),
    },
    rules: ['gdpr-consent', 'context-integrity']
  });

  if (!audit.passed) {
    throw new Error(`Handoff blocked: ${audit.violations.join(', ')}`);
  }

  return { ...context, vexTraceId: audit.traceId };
};
